  assign fifo_inputL_deqP_rl_PLUS_1__q2 = fifo_inputL_deqP_rl + 2'd1 ;
  assign fifo_inputL_enqP_rl_PLUS_1__q1 = fifo_inputL_enqP_rl + 2'd1 ;
  assign fifo_inputR_deqP_rl_PLUS_1__q4 = fifo_inputR_deqP_rl + 2'd1 ;
  assign fifo_inputR_enqP_rl_PLUS_1__q3 = fifo_inputR_enqP_rl + 2'd1 ;
  assign fifo_out_deqP_rl_PLUS_1__q6 = fifo_out_deqP_rl + 2'd1 ;
