  assign upd__h2164 = { 1'd0, fifo_inputL_enqP_rl_PLUS_1__q1[0] } ;
  assign upd__h3201 = { 1'd0, fifo_inputL_deqP_rl_PLUS_1__q2[0] } ;
  assign upd__h5377 = { 1'd0, fifo_inputR_enqP_rl_PLUS_1__q3[0] } ;
