      WILL_FIRE_RL_doFlowLeft:
	  upd__h7538 = MUX_fifo_out_data_0_lat_0$wset_1__VAL_1;
      WILL_FIRE_RL_doFlowRight:
	  upd__h7538 = MUX_fifo_out_data_0_lat_0$wset_1__VAL_2;
      WILL_FIRE_RL_doAddTwo: upd__h7538 = adder$getRes;
