        fifo_inputL_data_0_dummy2_0 <= `BSV_ASSIGNMENT_DELAY 1'd1;
	fifo_inputL_data_0_dummy2_1 <= `BSV_ASSIGNMENT_DELAY 1'd1;
	fifo_inputL_data_0_rl <= `BSV_ASSIGNMENT_DELAY 16'hAAAA;
	fifo_inputL_deqP_dummy2_0 <= `BSV_ASSIGNMENT_DELAY 1'd1;
